───────────────────────────────────────────────────────────── */
function TechnicalDetails({ silData, best_k, profiles }) {
  const [open, setOpen] = useState(false);

  const bestScore = silData.find(d => d.best)?.score ?? 0;
  const quality =
    bestScore >= 0.5 ? { label: "Strong",   color: "#15803d", bg: "#f0fdf4", border: "#bbf7d0" } :
    bestScore >= 0.3 ? { label: "Moderate", color: "#b45309", bg: "#fffbeb", border: "#fde68a" } :
                       { label: "Weak",     color: "#be123c", bg: "#fef2f2", border: "#fecaca" };

  return (
    <div className="tech-details">
      {/* ── Intuitive summary (always visible) ── */}
      <div className="tech-summary-row">
        <div>
          <p className="chart-title" style={{ marginBottom: 4 }}>Cluster Quality</p>
          <div className="tech-quality-badge" style={{
            background: quality.bg,
            border: `1px solid ${quality.border}`,
            color: quality.color,
          }}>
            {quality.label === "Strong"   ? "✅" :
             quality.label === "Moderate" ? "⚡" : "⚠️"}
            &nbsp;{quality.label} separation
            &nbsp;<span style={{ fontFamily: "var(--font-mono)", fontSize: 11 }}>
              ({bestScore.toFixed(3)})
            </span>
          </div>
          <p className="tech-quality-note">
            {quality.label === "Strong"
              ? `${best_k} segments are well-separated and distinct.`
              : quality.label === "Moderate"
              ? `${best_k} segments have some overlap — results are useful but not perfect.`
              : `Segments overlap significantly — interpret with caution.`}
          </p>
        </div>

        {/* Toggle */}
        <button className="tech-toggle-btn" onClick={() => setOpen(o => !o)}>
          {open ? "Hide details ↑" : "Show details ↓"}
        </button>
      </div>

      {/* ── Collapsible: silhouette bar chart ── */}
      {open && (
        <div className="tech-collapsible">
          <p className="chart-title" style={{ marginBottom: 8 }}>
            Silhouette Score by k
            <span style={{ fontWeight: 400, color: "#8a8680", marginLeft: 6 }}>
              (higher = better cluster separation)
            </span>
          </p>
          <ResponsiveContainer width="100%" height={150}>
            <BarChart data={silData} margin={{ left: -10, right: 4, top: 4, bottom: 0 }}>
              <XAxis dataKey="k"
                tick={{ fill: "#8a8680", fontSize: 11, fontFamily: "IBM Plex Mono" }}
                axisLine={false} tickLine={false} />
              <YAxis
                tick={{ fill: "#8a8680", fontSize: 10, fontFamily: "IBM Plex Mono" }}
                axisLine={false} tickLine={false} domain={[0, 1]} />
              <Tooltip contentStyle={TOOLTIP_STYLE} cursor={{ fill: "rgba(0,0,0,0.03)" }} />
              <Bar dataKey="score" radius={[4,4,0,0]}>
                {silData.map((e, i) => (
                  <Cell key={i} fill={e.best ? "#1d4ed8" : "#e2e0db"} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
          <p className="chart-note">Blue = selected k={best_k}</p>
        </div>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   AI BRIEFING
───────────────────────────────────────────────────────────── */
function AiBriefing({ profiles, meta, summary, analysis }) {
  const [text,   setText]   = useState("");
  const [status, setStatus] = useState("loading");

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await fetch(`${API}/ai/summary`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ profiles, meta, summary, analysis }),
        });
        if (!res.ok) throw new Error("summary failed");
        const reader = res.body.getReader();
        const dec    = new TextDecoder();
        let   full   = "";
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          if (cancelled) return;
          full += dec.decode(value, { stream: true });
          setText(full);
        }
        if (!cancelled) setStatus("done");
      } catch {
        if (!cancelled) setStatus("error");
      }
    })();
    return () => { cancelled = true; };
  }, []);

  if (status === "error") return null;

  return (
    <div className="ai-briefing">
      <div className="ai-briefing-label">
        <span className="ai-briefing-icon">🧠</span>
        AI Briefing
      </div>
      <p className="ai-briefing-text">
        {text || <span className="ai-briefing-skeleton" />}
        {status === "loading" && text && <span className="ai-briefing-cursor" />}
      </p>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   ACTION PLAN  — now calls onRowsParsed to share tips with cards
───────────────────────────────────────────────────────────── */
function ActionPlan({ profiles, meta, summary, onRowsParsed }) {
  const [status,   setStatus]   = useState("idle");
  const [markdown, setMarkdown] = useState("");
  const [errorMsg, setErrorMsg] = useState("");

  const parseTable = (md) => {
    const lines = md.trim().split("\n").filter(l => l.trim().startsWith("|"));
    if (lines.length < 2) return null;
    const parseRow = l => l.split("|").slice(1, -1).map(c => c.trim());
    return { headers: parseRow(lines[0]), rows: lines.slice(2).map(parseRow) };
  };

  const generate = async () => {
    setStatus("loading");
    setMarkdown("");
    setErrorMsg("");
    try {
      const res = await fetch(`${API}/ai/action-plan`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ profiles, meta, summary }),
      });
      if (!res.ok) {
        const d = await res.json().catch(() => ({}));
        throw new Error(d.detail || "Request failed");
      }
      const reader = res.body.getReader();
      const dec    = new TextDecoder();
      let   full   = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        full += dec.decode(value, { stream: true });
        setMarkdown(full);
      }
      setStatus("done");
      // Share parsed rows upward so segment cards can show quick tips
      const t = parseTable(full);
      if (t && onRowsParsed) onRowsParsed(t.rows);
    } catch (e) {
      setErrorMsg(e.message);
      setStatus("error");
    }
  };

  const table = status === "done" ? parseTable(markdown) : null;

  return (
    <div className="ai-tool-card">
      <div className="ai-tool-card-header">
        <div className="ai-tool-card-title">
          <span>📋</span> Action Plan
        </div>
        <button className="action-plan-btn" onClick={generate} disabled={status === "loading"}>
          {status === "loading" ? <><span className="ap-spinner" /> Generating…</>
           : status === "done"  ? <>↻ Regenerate</>
           : <>✨ Generate</>}
        </button>
      </div>

      {status === "idle" && (
        <p className="ai-tool-empty">
          Get AI-powered marketing recommendations for each segment.
          Tips will also appear on each segment card once generated.
        </p>
      )}
      {status === "loading" && !markdown && (
        <div className="action-plan-loading">
          <span className="ap-spinner" /> Asking AI for recommendations…
        </div>
      )}
      {status === "error" && (
        <div className="action-plan-error">⚠️ {errorMsg}</div>
      )}
      {markdown && (
        table ? (
          <div className="action-plan-table-wrap">
            <table>
              <thead><tr>{table.headers.map((h, i) => <th key={i}>{h}</th>)}</tr></thead>
              <tbody>
                {table.rows.map((row, i) => (
                  <tr key={i}>{row.map((cell, j) => <td key={j}>{cell}</td>)}</tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <pre className="action-plan-raw">{markdown}</pre>
        )
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────
   AI CHAT
───────────────────────────────────────────────────────────── */
const SUGGESTIONS = [
  "Which segment should I focus on first?",
  "Who are my most valuable customers?",
  "What are my top selling products?",
  "Which segment is most at risk of churning?",
  "What's my best sales day of the week?",
  "What % of revenue do my top segment drive?",
];

function AiChat({ context }) {
  const [messages,  setMessages]  = useState([]);
  const [input,     setInput]     = useState("");
  const [streaming, setStreaming] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth", block: "nearest" });
  }, [messages]);

  const send = useCallback(async (text) => {
    const msg = (text || input).trim();
    if (!msg || streaming) return;
    setInput("");
    const userMsg = { role: "user", content: msg };
    setMessages(prev => [...prev, userMsg]);
    setStreaming(true);
    setMessages(prev => [...prev, { role: "assistant", content: "" }]);
    try {
      const res = await fetch(`${API}/ai/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: msg, history: messages, context }),
      });
      if (!res.ok) throw new Error((await res.json().catch(() => ({}))).detail || "failed");
      const reader = res.body.getReader();
      const dec    = new TextDecoder();
      let   full   = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        full += dec.decode(value, { stream: true });
        setMessages(prev => [...prev.slice(0, -1), { role: "assistant", content: full }]);
      }
    } catch (e) {
      setMessages(prev => [...prev.slice(0, -1), { role: "assistant", content: `⚠️ ${e.message}` }]);
    } finally {
      setStreaming(false);
    }
  }, [input, streaming, messages, context]);

  return (
    <div className="ai-tool-card ai-chat-card">
      <div className="ai-tool-card-header">
        <div className="ai-tool-card-title">
          <span>🧠</span> Ask Your Data
          <span className="ai-chat-badge">AI</span>
        </div>
        {messages.length > 0 && (
          <button className="ai-chat-clear" onClick={() => setMessages([])}>Clear</button>
        )}
      </div>

      {messages.length === 0 && (
        <div className="ai-chat-suggestions">
          {SUGGESTIONS.map((s, i) => (
            <button key={i} className="suggestion-chip" onClick={() => send(s)}>{s}</button>
          ))}
        </div>
      )}

      <div className="ai-chat-messages">
        {messages.length === 0 ? (
          <div className="ai-chat-empty">
            <span className="ai-chat-empty-icon">💬</span>
            <p className="ai-chat-empty-text">Ask anything about your segments</p>
          </div>
        ) : messages.map((m, i) => (
          <div key={i} className={`chat-msg chat-msg-${m.role === "user" ? "user" : "ai"}`}>
            <div className="chat-msg-avatar">{m.role === "user" ? "👤" : "🧠"}</div>
            <div className="chat-msg-bubble">
              {m.role === "assistant" && m.content === "" ? (
                <div className="chat-typing">
                  <span className="chat-typing-dot" />
                  <span className="chat-typing-dot" />
                  <span className="chat-typing-dot" />
                </div>
              ) : m.content}
            </div>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>

      <div className="ai-chat-input-row">
        <textarea
          className="ai-chat-input"
          placeholder="Ask a question about your data…"
          value={input}
          rows={1}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } }}
          disabled={streaming}
        />
        <button className="ai-chat-send" onClick={() => send()}
          disabled={!input.trim() || streaming}>↑</button>
      </div>
    </div>
  );
}

